from autogen import GroupChat, GroupChatManager
import re
def detect_loops(chat_history):
    recent_msgs = chat_history[-10:]
    patterns = []
    for msg in recent_msgs:
        content = msg.get('content', '')
        if len(content) > 50:
            patterns.append(re.sub(r'\s+', ' ', content.lower())[:100])
    if len(patterns) > 3:
        for i in range(len(patterns)-3):
            if all(p1 == p2 for p1, p2 in zip(patterns[i:i+3], patterns[i+1:i+4])):
                return True
    return False

# Usage in agent
chat_history = groupchat.messages
if detect_loops(chat_history):
    print('INFINITE LOOP DETECTED')

import re
def scan_unsafe_code(code_content):
    dangerous_patterns = [
        r'rm\s+-rf',
        r'del\s+\\*\.', 
        r'exec\(input\(',
        r'subprocess\.call\([\s\S]*shell=True',
        r'open\([\s\S]*wb',
    ]
    for pattern in dangerous_patterns:
        if re.search(pattern, code_content, re.IGNORECASE):
            return {'safe': False, 'risk': pattern}
    return {'safe': True}

# In reply function
def safe_code_executor(message):
    if '```python' in message:
        code = re.search(r'```python\n([\s\S]*?)```', message)
        if code:
            result = scan_unsafe_code(code.group(1))
            if not result['safe']:
                return 'ERROR: Unsafe code detected'
    return message

def track_token_budget(messages, budget=50000):
    total_tokens = 0
    for msg in messages:
        # Simple token estimation
        content = msg.get('content', '')
        total_tokens += len(content) // 4 + 100  # Rough estimation
    if total_tokens > budget:
        return {
            'over_budget': True,
            'current': total_tokens,
            'budget': budget
        }
    return {'over_budget': False}

# Check before each reply
def budget_check(groupchat):
    status = track_token_budget(groupchat.messages)
    if status['over_budget']:
        groupchat.terminate()
        return 'Token budget exceeded'

