from autogen import AssistantAgent

class ValidatorAgent(AssistantAgent):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.validation_threshold = 0.8

    def validate_consensus(self, messages):
        conclusions = []
        for msg in messages[-5:]:
            if 'CONCLUSION' in msg['content'].upper():
                conclusions.append(msg['content'])

        if len(conclusions) >= 3:
            agreements = sum(1 for c in conclusions if any(word in c for word in conclusions[0].split()))
            return agreements / len(conclusions) > self.validation_threshold
        return False

# Usage
validator = ValidatorAgent(
    name='Validator',
    system_message='Validate conclusions from other agents',
    llm_config=llm_config
)

def consensus_check(sender):
    if validator.validate_consensus(sender.groupchat.messages):
        return True
    return 'Requires further validation'
